CREATE OR REPLACE FUNCTION calculate_disf(
    air_temp_c NUMERIC,
    atmos_transparency NUMERIC,
    humidity_rate NUMERIC,
    lunar_dist_deg NUMERIC
)
RETURNS NUMERIC AS $$
DECLARE
    disf_value NUMERIC;
BEGIN
    disf_value := (10 - ABS(air_temp_c - 15) / 10.0) 
                  * atmos_transparency 
                  * (1 - humidity_rate / 200.0) 
                  * ((100 - lunar_dist_deg) / 100.0);

    RETURN disf_value;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION calculate_disf(
    air_temp_c NUMERIC,
    atmos_transparency NUMERIC,
    humidity_rate NUMERIC,
    lunar_dist_deg NUMERIC,
    min_threshold NUMERIC DEFAULT 0
)
RETURNS NUMERIC AS $$
DECLARE
    disf_value NUMERIC;
BEGIN
    disf_value := (10 - ABS(air_temp_c - 15) / 10.0) 
                  * atmos_transparency 
                  * (1 - humidity_rate / 200.0) 
                  * ((100 - lunar_dist_deg) / 100.0);

    -- Ensure the returned value is never below the minimum threshold
    IF disf_value < min_threshold THEN
        RETURN min_threshold;
    ELSE
        RETURN disf_value;
    END IF;
END;
$$ LANGUAGE plpgsql;

